/// Tracks the history of a CDU specific to a reasoning path.
#[derive(Debug, Clone)]
pub struct HybridLogicalClock {
    /// The total number of times this CDU was involved in a successful Path replay.
    pub success_count: u64,
    /// The total number of times this CDU was involved in a failed/KO branch.
    pub failure_count: u64,
    /// A map where the key is the ReasoningPath (Concurrent/Cascading) and the value
    /// is the last 'tick' or version number associated with that path's processing.
    pub path_ticks: HashMap<ReasoningPath, u64>,
}

impl HybridLogicalClock {
    pub fn new() -> Self {
        HybridLogicalClock {
            success_count: 0,
            failure_count: 0,
            path_ticks: HashMap::new(),
        }
    }
}

