// Helper trait for easy ID generation/retrieval
pub trait Identifiable {
    fn id(&self) -> HlcId;
    fn new_id() -> HlcId;
}

impl Identifiable for CausalDataUnit {
    fn id(&self) -> HlcId {
        match self {
            CausalDataUnit::Task(t) => t.id,
            CausalDataUnit::Step(s) => s.id,
            CausalDataUnit::Path(p) => p.id,
            CausalDataUnit::Axiom(a) => a.id,
            CausalDataUnit::Ko(k) => k.id,
            CausalDataUnit::Ok(o) => o.id,
        }
    }
    fn new_id() -> HlcId { HlcId::new() }
}
